import {
  publicMarketplaceCatalog,
  publicMarketplaceCatalogCount,
  publicMarketplaceCatalogSourceUrl,
  type MarketplaceCatalogEntry,
} from "./marketplaceCatalog";

export type CurationStatus = "direct" | "inferred" | "curated" | "blocked";

export type ReferenceResourceSeed = {
  resourceId?: string;
  sortOrder?: number;
  title: string;
  url: string;
  sourceType: string;
  theme: string;
  note: string;
  evidenceLevel: string;
  extractionStatus: CurationStatus;
  scope?: "report_specific" | "background";
  accessedAt?: string;
  contentHash?: string;
  sourceArtifact?: string;
  usedFor?: string[];
};

export type SampleReportRowSeed = {
  sortOrder: number;
  groupTitle: string;
  item: string;
  brandName: string;
  geneticAnalysis: string;
  description?: string;
  genes: string[];
  sourceLabel: string;
  sourceResourceIds?: string[];
  sourceBindingStatus?: "exact" | "curated" | "sample_label_only" | "unavailable";
  sourceBindingNote?: string;
  extractionStatus: CurationStatus;
};

export type GenotypeSummarySeed = {
  sortOrder: number;
  tier: string;
  gene: string;
  variantId: string;
  genotype: string;
  effect: string;
  phenotype: string;
  extractionStatus: CurationStatus;
};

export type LocalTestFixtureSeed = {
  packageSlug: string;
  datasetId: string;
  packageVersion: string;
  reportPurpose?: string;
  missingInputPolicy?: string;
  consumerTone?: string;
  inputManifest: {
    hash: string;
    genomeBuild: string;
    rawGenomeReturned: boolean;
    source: string;
  };
  genomeEvidence: Array<{
    inputId: string;
    rsid?: string;
    starAllele?: string;
    haplotype?: string;
    gene: string;
    observedValue: string;
    assembly: string;
    matchStatus: string;
    sourceFile?: string;
    sourceArtifact?: string;
  }>;
  referenceResources: Array<{
    id: string;
    title: string;
    sourceType: string;
    evidenceLevel: string;
    usedFor: string[];
  }>;
  expectedAssertions: {
    noRawGenomeInOutput: boolean;
    everyFindingHasReference: boolean;
    missingInputsAreExplicit: boolean;
    probabilitiesOnlyInAppendix: boolean;
    consumerLanguage: boolean;
  };
};

export type FormalFieldSeed = {
  sortOrder: number;
  sourceLabel: string;
  observedField: string;
  outputPath: string;
  status: "covered" | "pending" | "not_applicable";
  notes: string;
};

export type ReportPackageSeed = {
  slug: string;
  title: string;
  subtitle: string;
  category: string;
  provider: string;
  version: string;
  status: string;
  summary: string;
  detail: string;
  audience: string;
  claimScope: string;
  sourceUrl: string;
  marketplaceUrl: string;
  priceLabel: string;
  catalogCategories: string[];
  catalogSource: string;
  curationStatus: CurationStatus;
  sampleReportStatus: string;
  sourceArtifacts: string[];
  curationCompleteness: {
    catalog: boolean;
    detail: boolean;
    sampleReport: boolean;
    references: boolean;
    localFixture: boolean;
    prompt: boolean;
    outputFormat: boolean;
    formalFields: boolean;
    citationBindings: boolean;
    notes: string[];
  };
  tags: string[];
  visibleFields: string[];
  genomeInputs: Array<{
    id: string;
    kind: string;
    label: string;
    required: boolean;
    assembly: string;
    missingDataBehavior: string;
  }>;
  references: ReferenceResourceSeed[];
  prompt: {
    title: string;
    promptVersion?: string;
    promptHash?: string;
    outputFormatHash?: string;
    deterministicPrompt: string;
    inputContract: string[];
    outputContract: string[];
    appendixPolicy: string;
    probabilityDisclosure: string;
    safetyNotes: string[];
    extractionStatus: CurationStatus;
  } | null;
  sampleRows: SampleReportRowSeed[];
  genotypeSummary: GenotypeSummarySeed[];
  localTestFixture: LocalTestFixtureSeed | null;
  formalFields: FormalFieldSeed[];
  outputSections: Array<{
    sortOrder: number;
    title: string;
    purpose: string;
    expectedFields: Array<{
      key: string;
      label: string;
      description: string;
      type: string;
      required: boolean;
      fieldPath?: string;
      citationRequired?: boolean;
      sourceBinding?: string;
      formalSourceField?: string;
      allowsUnavailable?: boolean;
    }>;
  }>;
};

