const authenticatedDetailEvidenceArtifactFor = (slug: string) =>
  authenticatedDetailEvidenceArtifactBySlug[slug] ?? null;

const authenticatedDetailEvidenceNoteFor = (artifactPath: string) =>
  `Authenticated detail-page evidence captured in ${artifactPath} confirms the exact marketplace route plus available title, product, publisher/provider, sample-report, and detail-boundary metadata; page overview or card text is used only for marketplace positioning, not local genetic conclusions.`;

const publicCatalogSeedEntries: CatalogSeedEntry[] = publicMarketplaceCatalog.map((entry) => ({
  title: entry.title,
  slug: entry.slug,
  marketplaceUrl: entry.marketplaceUrl,
  categories: entry.categories,
  primaryCategory: entry.primaryCategory,
  provider: entry.provider || "Sequencing.com",
  priceLabel: entry.priceLabel || "Unknown",
  sourceUrl: entry.sourceUrl,
  ctaLabel: entry.priceLabel === "Free" ? "Get App" : "Get Report",
  sourceArtifacts: [entry.sourceUrl, sourceUrls.publicCatalogJson],
  notes: [
    `Public aggregate marketplace catalog extracted this item from ${publicMarketplaceCatalogCount} unique public entries.`,
  ],
}));

const catalogSeedEntries = [...publicCatalogSeedEntries, ...authenticatedCatalogOnly].reduce<CatalogSeedEntry[]>(
  (entries, entry) => {
    if (entries.some((candidate) => candidate.slug === entry.slug)) {
      return entries;
    }
    entries.push(entry);
    return entries;
  },
  [],
);

const claimScopeForCategory = (category: string) => {
  if (category === "Medication") return "pharmacogenomics";
  if (category === "Health") return "medical-risk";
  if (category === "Ancestry") return "ancestry-education";
  if (category === "Bioinformatics") return "genome-analysis-tool";
  if (category === "DNA Test Kit Bundles") return "test-kit-bundle";
  if (category === "Test Kits") return "test-kit";
  if (category === "Sequencing Apps") return "sequencing-app";
  if (category === "Draft") return "draft-report";
  return "wellness";
};

const dedupeReferences = (references: ReferenceResourceSeed[]) => {
  const seen = new Set<string>();
  return references
    .filter((reference) => {
      const key = reference.resourceId ?? reference.title;
      if (seen.has(key)) {
        return false;
      }
      seen.add(key);
      return true;
    })
    .map((reference, index) => ({
      ...reference,
      sortOrder: index + 1,
    }));
};

const referencesForCatalogEntry = (entry: CatalogSeedEntry) => {
  const title = entry.title.toLowerCase();
  const categories = entry.categories.map((category) => category.toLowerCase());
  const primaryCategory = entry.primaryCategory.toLowerCase();
  const references: ReferenceResourceSeed[] = [
    sharedReferences[0],
    catalogReferenceLibrary.cdcGeneticTesting,
    catalogReferenceLibrary.medlinePlusGenetics,
  ];

  if (["health", "draft", "lifestyle", "beauty"].includes(primaryCategory) || categories.includes("health")) {
    references.push(
      catalogReferenceLibrary.cdcFamilyHealthHistory,
      sharedReferences[1],
      sharedReferences[2],
      sharedReferences[3],
    );
  }

  if (primaryCategory === "ancestry" || categories.includes("ancestry")) {
    references.push(
      catalogReferenceLibrary.thousandGenomes,
      catalogReferenceLibrary.medlinePlusGeneticAncestryTesting,
      catalogReferenceLibrary.medlinePlusDtcRisksBenefits,
    );
  }

  if (/mitochondrial|mtdna|maternal|haplogroup/.test(title)) {
    references.push(
      catalogReferenceLibrary.medlinePlusMitochondrialDna,
      catalogReferenceLibrary.mitomap,
      catalogReferenceLibrary.medlinePlusGeneticAncestryTesting,
    );
  }

  if (primaryCategory === "fitness" || categories.includes("fitness") || /athletic|fitness|trainer|strength/.test(title)) {
    references.push(catalogReferenceLibrary.medlinePlusAthleticPerformance, sharedReferences[2]);
  }

  if (primaryCategory === "nutrition" || categories.includes("nutrition") || /nutrition|nutri|metabolic|glucose/.test(title)) {
    references.push(
      catalogReferenceLibrary.nutritionalGenomicsDtcReview,
      catalogReferenceLibrary.medlinePlusLactoseIntolerance,
      catalogReferenceLibrary.medlinePlusMcm6,
      sharedReferences[2],
    );
  }

  if (/sleep|chronotype|circadian|insomnia|narcolepsy|restless leg|dream|rem/.test(title)) {
    references.push(
      catalogReferenceLibrary.medlinePlusSleepDisorders,
      catalogReferenceLibrary.medlinePlusHealthySleep,
      catalogReferenceLibrary.nigmsCircadianRhythms,
      sharedReferences[1],
      sharedReferences[2],
    );
  }

  if (
    primaryCategory === "beauty" ||
    categories.includes("beauty") ||
    /physical appearance|hair color|hair texture|eye color|skin pigmentation|freckles/.test(title)
  ) {
    references.push(
      catalogReferenceLibrary.medlinePlusEyeColor,
      catalogReferenceLibrary.medlinePlusHairColor,
      catalogReferenceLibrary.medlinePlusHairTexture,
      catalogReferenceLibrary.medlinePlusOca2,
      catalogReferenceLibrary.medlinePlusMc1r,
      catalogReferenceLibrary.medlinePlusDtcTestTypes,
    );
  }

  if (/hair loss|bald|balding|androgenetic alopecia|pattern hair/.test(title)) {
    references.push(
      catalogReferenceLibrary.medlinePlusAndrogeneticAlopecia,
      catalogReferenceLibrary.medlinePlusAr,
      catalogReferenceLibrary.medlinePlusHairLoss,
      catalogReferenceLibrary.medlinePlusMalePatternBaldness,
      catalogReferenceLibrary.medlinePlusDtcTestTypes,
      sharedReferences[1],
      sharedReferences[2],
    );
  }

  if (/alzheimer|apoe|brain|cognitive|dementia/.test(title)) {
    references.push(catalogReferenceLibrary.medlinePlusAlzheimers);
  }

  if (/mthfr|folate|folic/.test(title)) {
    references.push(
      wellnessReferences.find((reference) => reference.resourceId === "cdc-mthfr-folic-acid") ??
        catalogReferenceLibrary.cdcGeneticTesting,
    );
  }

  if (/\bblood type\b|\babo\b|\brhd\b|\brh factor\b/.test(title)) {
    references.push(catalogReferenceLibrary.medlinePlusBloodTyping, catalogReferenceLibrary.ncbiAboBloodGroup);
  }

  if (/cancer|tumou?r|oncology|melanoma|breast|colon|prostate|ovarian|pancreatic|thyroid|skin/.test(title)) {
    references.push(catalogReferenceLibrary.nciCancerGeneticTesting, sharedReferences[3]);
  }

  if (/pharmac|pharma|anesthesiologist|medication|drug|pgx|aspirin/.test(title)) {
    references.push(
      catalogReferenceLibrary.cdcPharmacogenomics,
      catalogReferenceLibrary.medlinePlusPharmacogeneticTests,
      catalogReferenceLibrary.nhgriPharmacogenomics,
      wellnessReferences.find((reference) => reference.resourceId === "pharmgkb") ?? catalogReferenceLibrary.cdcGeneticTesting,
      wellnessReferences.find((reference) => reference.resourceId === "cpic") ?? catalogReferenceLibrary.cdcGeneticTesting,
      wellnessReferences.find((reference) => reference.resourceId === "fda-pgx-associations") ?? catalogReferenceLibrary.cdcGeneticTesting,
      wellnessReferences.find((reference) => reference.resourceId === "fda-pgx-biomarkers-labeling") ??
        catalogReferenceLibrary.cdcGeneticTesting,
      catalogReferenceLibrary.pharmcat,
      catalogReferenceLibrary.pharmvar,
    );
  }

  if (
    primaryCategory === "bioinformatics" ||
    primaryCategory === "test kits" ||
    categories.includes("bioinformatics") ||
    categories.includes("test kits") ||
    /\b(?:kit|sequencing|variant|imputation|coverage)\b/.test(title) ||
    /\b(?:complete genome analysis|whole genome analysis|genome analysis|genomic analysis)\b/.test(title)
  ) {
    references.push(
      catalogReferenceLibrary.ensemblVep,
      catalogReferenceLibrary.ensemblVariantConsequences,
      catalogReferenceLibrary.sequenceOntology,
      catalogReferenceLibrary.ncbiDbSnp,
      catalogReferenceLibrary.ncbiClinVar,
      catalogReferenceLibrary.ncbiGtr,
      catalogReferenceLibrary.thousandGenomes,
      sharedReferences[2],
    );
  }

  return dedupeReferences(references);
};

const backgroundReferenceNoteFor = (entry: CatalogSeedEntry) =>
  `A curated background reference pack is attached for ${entry.primaryCategory} / ${entry.categories.join(", ")} reports. It supports safe framing and candidate evidence lookup, but it is not the recovered Sequencing.com mock-report bibliography.`;

