type ConditionRiskBoundaryPackageConfig = {
  slug: string;
  reportTitle: string;
  conditionLabel: string;
  conditionGroup: string;
  claimScope: string;
  datasetId: string;
  summary: string;
  detail: string;
  promptFocus: string;
  extraPromptLines?: string[];
  unavailableEvidence: string;
  modelLabel: string;
  prohibitedClaims: string;
  tags: string[];
  visibleFields: string[];
  conditionReferences: ReferenceResourceSeed[];
};

const fixtureReferenceFromSeed = (
  reference: ReferenceResourceSeed,
  usedFor: string[],
): LocalTestFixtureSeed["referenceResources"][number] => ({
  id: reference.resourceId ?? reference.title,
  title: reference.title,
  sourceType: reference.sourceType,
  evidenceLevel: reference.evidenceLevel,
  usedFor,
});

const conditionRiskBoundaryReferences = [
  catalogReferenceLibrary.cdcGeneticTesting,
  catalogReferenceLibrary.medlinePlusGenetics,
  catalogReferenceLibrary.medlinePlusComplexDisorders,
  catalogReferenceLibrary.fdaDtcTests,
  sharedReferences[1],
  sharedReferences[2],
  catalogReferenceLibrary.nciCancerGeneticTesting,
];

const makeCancerRiskBoundaryConfig = ({
  slug,
  reportTitle,
  conditionLabel,
  extraTags = [],
}: {
  slug: string;
  reportTitle: string;
  conditionLabel: string;
  extraTags?: string[];
}): ConditionRiskBoundaryPackageConfig => ({
  slug,
  reportTitle,
  conditionLabel,
  conditionGroup: "Cancer risk boundary",
  claimScope: "cancer genetics education",
  datasetId: `synthetic-${slug}-cancer-boundary-context-v1`,
  summary: `A local-agent scaffold for ${conditionLabel} context that reports only supplied derived evidence and explicitly marks validated cancer-risk models, clinical history, screening context, and authenticated sample rows unavailable.`,
  detail: `This package uses public genetic-testing, inherited-cancer, DTC limitations, PRS, and GWAS references to produce conservative ${conditionLabel} boundary context. It does not estimate cancer risk, diagnose cancer, infer carrier status, classify variants, recommend screening or prevention steps, or replace genetic counseling. Authenticated Sequencing.com mock-report rows are still pending.`,
  promptFocus: `${conditionLabel} education, inherited-cancer testing limits, model-unavailable disclosure, and genetic-counseling review boundaries`,
  unavailableEvidence:
    "validated pathogenic-variant screen, calibrated cancer PRS, ancestry applicability metadata, age, sex where relevant, personal cancer history, family history, tumor testing, clinical screening history, prevention-plan context, and authenticated sample-report rows",
  modelLabel: `${reportTitle} model`,
  prohibitedClaims:
    "diagnose cancer, estimate personal cancer risk, infer carrier status, classify variants, provide an all-clear result, recommend screening, recommend prevention steps, recommend medication, recommend surgery, recommend treatment, or replace genetic counseling",
  tags: ["cancer-risk", "genetic-testing", "prs-unavailable", "genetic-counseling", "model-unavailable", ...extraTags],
  visibleFields: [
    `${reportTitle} model unavailable`,
    "Validated pathogenic-variant screen unavailable",
    "Calibrated cancer PRS unavailable",
    "Family history, clinical screening, tumor testing, and authenticated sample rows unavailable",
    "No diagnosis, personal risk estimate, carrier-status, screening, prevention, medication, surgery, treatment, or actionability claims",
  ],
  conditionReferences: conditionRiskBoundaryReferences,
});

