const makeImmuneDiseaseRiskSiblingLocalTestFixture = (
  config: ImmuneInflammatoryConditionBoundaryPackageConfig,
  fixture: LocalTestFixtureSeed,
  definition: DiseaseRiskSiblingSampleDefinition,
): LocalTestFixtureSeed => ({
  ...fixture,
  reportPurpose:
    `Consumer ${config.focusLabel} boundary context using supplied references plus observed sibling Disease Risk Genetic Test Report ${definition.focusLabel} while explicitly marking personal model and clinical/lab context unavailable.`,
  missingInputPolicy:
    `Report unavailable ${config.focusLabel} evidence explicitly; use the public sibling Disease Risk sample rows only as observed output structure and do not infer ${definition.prohibitedClaims} from local unavailable evidence or sample-only rows.`,
  referenceResources: [
    ...fixture.referenceResources,
    fixtureReferenceFromSeed(geneticTestingDiseaseRiskSampleReference, [
      "sibling_formal_fields",
      "sample_rows",
      "risk_label_table",
      "output_format",
    ]),
  ],
  genomeEvidence: fixture.genomeEvidence.map((evidence) => {
    if (evidence.inputId === `${config.slug}-model-unavailable`) {
      return {
        ...evidence,
        observedValue:
          `${config.unavailableEvidence} unavailable in this fixture; ${definition.sampleRowsNote}`,
      };
    }

    if (evidence.inputId === `${config.slug}-clinical-lab-context-unavailable`) {
      return {
        ...evidence,
        observedValue:
          `clinical diagnosis, symptoms, labs, inflammatory markers, immune evaluation, family history, medication context, environmental context, clinician interpretation, disease activity, flare context, and personal treatment context unavailable in this fixture; public Disease Risk Genetic Test Report sample PDF observed separately as sibling output-structure evidence for ${config.reportTitle}`,
      };
    }

    return evidence;
  }),
});

