const indefiniteArticleFor = (value: string) => (/^[aeiou]/i.test(value) ? "an" : "a");

const makeProfessionalHandoffConfig = ({
  slug,
  reportTitle,
  specialtyLabel,
  domainLabel,
  references,
  promptFocus,
  unavailableEvidence,
  prohibitedClaims,
  extraTags = [],
  extraVisibleFields = [],
}: {
  slug: string;
  reportTitle: string;
  specialtyLabel: string;
  domainLabel: string;
  references: ReferenceResourceSeed[];
  promptFocus: string;
  unavailableEvidence: string;
  prohibitedClaims: string;
  extraTags?: string[];
  extraVisibleFields?: string[];
}): ProfessionalHandoffPackageConfig => ({
  slug,
  reportTitle,
  specialtyLabel,
  domainLabel,
  claimScope: "consumer professional-handoff preparation",
  datasetId: `synthetic-${slug}-professional-handoff-context-v1`,
  summary: `A local-agent scaffold for ${indefiniteArticleFor(specialtyLabel)} ${specialtyLabel} handoff summary that organizes supplied genome-derived context and explicitly marks specialist review, clinical context, and authenticated sample rows unavailable.`,
  detail: `This package prepares consumer-readable ${specialtyLabel} discussion context using supplied genome-derived evidence and public reference resources. It is not a completed ${specialtyLabel} review and does not provide clearance, diagnosis, risk estimates, medication or procedure instructions, treatment recommendations, lab interpretation, reproductive decisions, or clinical actionability. Authenticated Sequencing.com mock-report rows are still pending.`,
  promptFocus,
  unavailableEvidence,
  prohibitedClaims,
  tags: ["professional-handoff", "consumer-shareable", "review-unavailable", "clinical-context-unavailable", ...extraTags],
  visibleFields: [
    `${reportTitle} handoff context`,
    `${specialtyLabel} review unavailable`,
    "Clinical history, current medications, symptoms, labs, procedure details, professional review, and authenticated sample rows unavailable",
    "No diagnosis, clearance, risk estimate, medication, procedure, treatment, supplement, diet, lab, screening, reproductive, or actionability claims",
    ...extraVisibleFields,
  ],
  references,
});

