const makeDiseaseRiskCancerSiblingLocalTestFixture = (
  config: ConditionRiskBoundaryPackageConfig,
  fixture: LocalTestFixtureSeed,
): LocalTestFixtureSeed => ({
  ...fixture,
  reportPurpose:
    `Consumer ${config.conditionLabel} boundary context using supplied references plus observed sibling Disease Risk Genetic Test Report cancer-category output structure.`,
  missingInputPolicy:
    `Report unavailable ${config.conditionLabel} evidence explicitly; use the public sibling Disease Risk sample rows only as observed output structure and do not diagnose cancer, estimate personal cancer risk, infer carrier or pathogenic-variant status, recommend screening, recommend prevention steps, recommend medication, recommend surgery, recommend treatment, or provide actionability from local unavailable evidence or sample-only rows.`,
  referenceResources: [
    ...fixture.referenceResources,
    fixtureReferenceFromSeed(geneticTestingDiseaseRiskSampleReference, [
      "sibling_formal_fields",
      "sample_rows",
      "risk_label_table",
      "output_format",
    ]),
  ],
  genomeEvidence: fixture.genomeEvidence.map((evidence) => {
    if (evidence.inputId === `${config.slug}-model-unavailable`) {
      return {
        ...evidence,
        observedValue:
          `validated ${config.conditionLabel} model, calibrated cancer PRS, pathogenic variant interpretation, inherited-cancer panel scope, ancestry applicability, family history, tumor testing, screening context, prevention context, and clinician or genetic-counselor review unavailable in this fixture; public Disease Risk Genetic Test Report sample PDF Cancers category table and heritable-component limitation observed as sibling output structure`,
      };
    }

    if (evidence.inputId === `${config.slug}-clinical-context-unavailable`) {
      return {
        ...evidence,
        observedValue:
          `clinical diagnosis, symptoms, screening findings, family history, tumor testing, treatment history, prevention context, and clinician interpretation unavailable in this fixture; public Disease Risk Genetic Test Report Cancers category table observed separately as output-structure evidence for ${config.reportTitle}`,
      };
    }

    return evidence;
  }),
});

