const makeSpecializedBoundaryPrompt = (config: SpecializedBoundaryPackageConfig) =>
  [
    `Generate a plain-English ${config.reportTitle} report from local genome-derived evidence and supplied reference resources.`,
    "Use only provided evidence and references. Do not invent genes, variants, classifications, scores, studies, symptoms, family history, clinical history, labs, imaging, vitals, diagnoses, medication context, pediatric context, source-tool output, or treatment conclusions.",
    "Write deterministic report sections first. Put probability, confidence, calibration status, missing data, and uncertainty only in the appendix.",
    "Do not request, copy, or emit raw genome data. Use only derived evidence rows.",
    "Use CDC, NIH, MedlinePlus, FDA, USPSTF, AAP, NHGRI PRS, GWAS Catalog, PGS Catalog, ClinGen, ClinVar, SNPedia/Promethease, and product identity references only as supplied in the input.",
    "Use plain English for general customers, not clinician-, pharmacology-, pediatric-, neurodevelopment-, psychiatric-, genetics-, or researcher-facing language.",
    `For this package, focus on ${config.promptFocus}.`,
    `If ${config.unavailableEvidence} are missing, mark those sections unavailable instead of inferring them.`,
    ...(config.extraPromptLines ?? []),
    `Do not ${config.prohibitedClaims}.`,
    `State that ${config.focusLabel} decisions require validated test scope, source-output provenance, clinical context, ancestry applicability when relevant, and qualified professional review for ${config.professionalReviewContext}.`,
    "Every result row must cite provided reference IDs using `sourceIds` or `sourceResourceIds`, or use `source-unavailable` when no supplied source applies.",
    "Return valid JSON matching the output contract. Do not include markdown outside JSON.",
  ].join("\n");

