const makeSpecializedDiseaseRiskSiblingLocalTestFixture = (
  config: SpecializedBoundaryPackageConfig,
  fixture: LocalTestFixtureSeed,
  definition: DiseaseRiskSiblingSampleDefinition,
): LocalTestFixtureSeed => ({
  ...fixture,
  reportPurpose:
    `Consumer ${config.focusLabel} using supplied references plus observed sibling Disease Risk Genetic Test Report ${definition.focusLabel} while explicitly marking personal model, source output, clinical context, and professional review unavailable.`,
  missingInputPolicy:
    `Report unavailable ${config.focusLabel} evidence explicitly; use the public sibling Disease Risk sample rows only as observed output structure and do not infer ${definition.prohibitedClaims} from local unavailable evidence or sample-only rows.`,
  referenceResources: [
    ...fixture.referenceResources,
    fixtureReferenceFromSeed(geneticTestingDiseaseRiskSampleReference, [
      "sibling_formal_fields",
      "sample_rows",
      "risk_label_table",
      "output_format",
    ]),
  ],
  genomeEvidence: fixture.genomeEvidence.map((evidence) => {
    if (evidence.inputId === `${config.slug}-model-output-unavailable`) {
      return {
        ...evidence,
        observedValue:
          `${config.unavailableEvidence} unavailable in this fixture; ${definition.sampleRowsNote}`,
      };
    }

    if (evidence.inputId === `${config.slug}-clinical-professional-context-unavailable`) {
      return {
        ...evidence,
        observedValue:
          `clinical diagnosis, symptoms, family history, medications, professional interpretation, and decision context unavailable in this fixture; public Disease Risk Genetic Test Report sample PDF observed separately as sibling output-structure evidence for ${config.reportTitle}`,
      };
    }

    if (evidence.inputId === `${config.slug}-authenticated-sample-unavailable`) {
      return {
        ...evidence,
        observedValue:
          `direct ${config.reportTitle} authenticated sample rows unavailable in this fixture; public Disease Risk Genetic Test Report sample PDF observed separately as sibling output-structure evidence`,
      };
    }

    return evidence;
  }),
});

