    const diseaseRiskSiblingSampleDefinition = diseaseRiskSiblingSampleDefinitions[report.slug];
    const hasDiseaseRiskSiblingSample = diseaseRiskSiblingSampleDefinition !== undefined;
    const hasOrganSystemSample =
      hasBloodTraitsSample ||
      hasRespiratoryHealthSample ||
      hasDiseaseRiskSample ||
      hasChronicPainSample ||
      hasChronicFatigueSample ||
      hasDysautonomiaOfficialOutputCapture ||
      hasDiseaseRiskSiblingSample;
